import { getContext, setContext } from 'svelte';
import {} from "../../general/icon";
class ToastManager {
    toasts = $state([]);
    show(message, options) {
        const id = Math.random().toString(36).slice(2);
        const newToast = { id, message, options };
        this.toasts = [...this.toasts, newToast];
        if (options?.duration !== 0) { // duration = 0 means infinite
            setTimeout(() => this.dismiss(id), options?.duration || 3000);
        }
        return id;
    }
    dismiss(id) {
        this.toasts = this.toasts.filter(toast => toast.id !== id);
    }
    // For custom toast components (advanced usage)
    showCustom(component, props, options) {
        const id = Math.random().toString(36).slice(2);
        const newToast = { id, message: '', options, component, props };
        this.toasts = [...this.toasts, newToast];
        if (options?.duration !== 0) {
            setTimeout(() => this.dismiss(id), options?.duration || 3000);
        }
        return id;
    }
}
const KEY = 'atom-forge:toast-manager';
export function createToastManager() {
    const manager = new ToastManager();
    setToastManager(manager);
    return manager;
}
export const getToastManager = () => getContext(KEY);
export const setToastManager = (manager) => setContext(KEY, manager);
